const salesItems = $('Read Sales Data').all();
const leadsItems = $('Read Leads Data').all();
const ordersItems = $('Read Orders Data').all();

const salesData = salesItems.map(i => i.json);
const totalSales = salesData.reduce((sum, r) => sum + (parseFloat(r.Amount) || 0), 0);
const salesCount = salesData.length;
const avgSale = salesCount > 0 ? (totalSales / salesCount).toFixed(2) : 0;

const leadsData = leadsItems.map(i => i.json);
const totalLeads = leadsData.length;
const qualifiedLeads = leadsData.filter(r => r.Status === 'Qualified').length;
const closedLeads = leadsData.filter(r => r.Status === 'Closed').length;
const conversionRate = totalLeads > 0 ? ((closedLeads / totalLeads) * 100).toFixed(1) : 0;

const ordersData = ordersItems.map(i => i.json);
const totalOrders = ordersData.length;
const completedOrders = ordersData.filter(r => r.Status === 'Completed').length;
const totalRevenue = ordersData.filter(r => r.Status === 'Completed').reduce((sum, r) => sum + (parseFloat(r.Amount) || 0), 0);
const avgOrder = completedOrders > 0 ? (totalRevenue / completedOrders).toFixed(2) : 0;

return [{ json: { totalSales, salesCount, avgSale, totalLeads, qualifiedLeads, closedLeads, conversionRate, totalOrders, completedOrders, totalRevenue, avgOrder, reportDate: new Date().toLocaleDateString('en-US') } }];

